sql:
SELECT keyword 
FROM movie_keywords 
WHERE keyword = 'toys';

external_knowledge:
- "modern movies" refers to movies released in the past five years (from the current year); 
- "highly rated" means an average rating greater than 7.5; 
- "widely appreciated" means having more than 100 helpful reviews; 
- "listing them in order of their popularity" refers to ordering the results in descending order based on the total helpful reviews.

